database_design.schema:
CREATE TABLE sheets (id BIGSERIAL PK, name TEXT, version BIGINT NOT NULL DEFAULT 0);
CREATE TABLE cells (
  sheet_id BIGINT NOT NULL REFERENCES sheets(id) ON DELETE CASCADE,
  ref TEXT NOT NULL, -- 'A1','B2'
  formula TEXT,
  value JSONB,
  err TEXT,
  updated_by BIGINT,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  cell_version BIGINT NOT NULL DEFAULT 0,
  PRIMARY KEY (sheet_id, ref)
);
CREATE TABLE cell_deps (
  sheet_id BIGINT NOT NULL,
  dependent_ref TEXT NOT NULL,
  depends_on_ref TEXT NOT NULL,
  PRIMARY KEY (sheet_id, dependent_ref, depends_on_ref)
);
CREATE INDEX ON cell_deps (sheet_id, depends_on_ref);
CREATE TABLE cell_history (id BIGSERIAL PK, sheet_id BIGINT, ref TEXT, formula TEXT, value JSONB, edited_by BIGINT, at TIMESTAMPTZ DEFAULT now());

