// src/services/recalcService.ts
import { pool } from '../infra/pg';
import { parseFormula, evalCell } from '../sheet/engine';
import { redis } from '../infra/redis';

export async function editCell(sheetId: number, ref: string, formula: string, userId: number, expectedSheetVersion: number) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)', [sheetId]);
    const sv = await client.query('SELECT version FROM sheets WHERE id=$1 FOR UPDATE', [sheetId]);
    if (!sv.rows[0]) { await client.query('ROLLBACK'); throw new Error('no_sheet'); }
    if (sv.rows[0].version !== expectedSheetVersion) { await client.query('ROLLBACK'); const all = await pool.query('SELECT ref, value, err, cell_version FROM cells WHERE sheet_id=$1', [sheetId]); return { conflict: true, version: sv.rows[0].version, cells: all.rows }; }
    const parsed = parseFormula(formula); // {deps: string[], ast}
    await client.query('DELETE FROM cell_deps WHERE sheet_id=$1 AND dependent_ref=$2', [sheetId, ref]);
    if (parsed.deps.length) {
      const vals = parsed.deps.map((_,i) => `($1,$2,$${i+3})`).join(',');
      await client.query(`INSERT INTO cell_deps(sheet_id, dependent_ref, depends_on_ref) VALUES ${vals}`, [sheetId, ref, ...parsed.deps]);
    }
    // detect cycle by BFS reaching self
    const cycle = await client.query(`WITH RECURSIVE rev(r, d) AS (SELECT depends_on_ref, 0 FROM cell_deps WHERE sheet_id=$1 AND dependent_ref=$2 UNION SELECT cd.depends_on_ref, r.d+1 FROM rev r JOIN cell_deps cd ON cd.sheet_id=$1 AND cd.dependent_ref=r.r WHERE r.d<200) SELECT 1 FROM rev WHERE r=$2 LIMIT 1`, [sheetId, ref]);
    if (cycle.rowCount! > 0) { await client.query('ROLLBACK'); return { error: 'circular' }; }
    // upsert this cell first
    const value = await evalCell(parsed.ast, async (depRef) => (await client.query('SELECT value FROM cells WHERE sheet_id=$1 AND ref=$2', [sheetId, depRef])).rows[0]?.value);
    await client.query('INSERT INTO cells(sheet_id, ref, formula, value, updated_by, cell_version) VALUES ($1,$2,$3,$4,$5,1) ON CONFLICT (sheet_id, ref) DO UPDATE SET formula=EXCLUDED.formula, value=EXCLUDED.value, updated_by=EXCLUDED.updated_by, updated_at=now(), cell_version=cells.cell_version+1', [sheetId, ref, formula, value, userId]);
    // BFS dependents and recalc in topo order
    const cascade = await client.query(`WITH RECURSIVE fwd(r, d) AS (SELECT dependent_ref, 1 FROM cell_deps WHERE sheet_id=$1 AND depends_on_ref=$2 UNION SELECT cd.dependent_ref, f.d+1 FROM fwd f JOIN cell_deps cd ON cd.sheet_id=$1 AND cd.depends_on_ref=f.r WHERE f.d<200) SELECT DISTINCT ON (r) r, d FROM fwd ORDER BY r, d DESC`, [sheetId, ref]);
    const ordered = cascade.rows.sort((a,b) => a.d - b.d);
    const diffs: any[] = [{ ref, value, cellVersion: 1 }];
    for (const row of ordered) {
      const cur = await client.query('SELECT formula FROM cells WHERE sheet_id=$1 AND ref=$2', [sheetId, row.r]);
      if (!cur.rows[0]?.formula) continue;
      try {
        const ast = parseFormula(cur.rows[0].formula).ast;
        const newV = await evalCell(ast, async (depRef) => (await client.query('SELECT value FROM cells WHERE sheet_id=$1 AND ref=$2', [sheetId, depRef])).rows[0]?.value);
        const upd = await client.query('UPDATE cells SET value=$1, err=NULL, cell_version=cell_version+1, updated_at=now() WHERE sheet_id=$2 AND ref=$3 RETURNING cell_version', [newV, sheetId, row.r]);
        diffs.push({ ref: row.r, value: newV, cellVersion: upd.rows[0].cell_version });
      } catch (e:any) {
        await client.query('UPDATE cells SET err=$1, value=NULL, cell_version=cell_version+1 WHERE sheet_id=$2 AND ref=$3', [String(e), sheetId, row.r]);
        diffs.push({ ref: row.r, err: String(e) });
      }
    }
    const newVer = await client.query('UPDATE sheets SET version = version + 1 WHERE id=$1 RETURNING version', [sheetId]);
    await client.query('COMMIT');
    return { ok: true, diffs, sheetVersion: newVer.rows[0].version };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

// src/socket/sheets.namespace.ts
import { Namespace } from 'socket.io';
import { editCell } from '../services/recalcService';
import { pool } from '../infra/pg';
export function registerSheetsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('sheet:open', async ({ sheetId }, ack) => {
      if (!await canRead(socket.data.user.id, sheetId)) return ack({ error: 'forbidden' });
      await socket.join(`sheet:${sheetId}`);
      const [s, c] = await Promise.all([
        pool.query('SELECT id, name, version FROM sheets WHERE id=$1', [sheetId]),
        pool.query('SELECT ref, formula, value, err, cell_version FROM cells WHERE sheet_id=$1', [sheetId]),
      ]);
      ack({ sheet: s.rows[0], cells: c.rows });
    });
    socket.on('cell:edit', async ({ sheetId, ref, formula, expectedSheetVersion }, ack) => {
      try {
        const res = await editCell(Number(sheetId), ref, formula, socket.data.user.id, expectedSheetVersion);
        if (res.error) return ack({ error: res.error });
        if ((res as any).conflict) return ack({ conflict: true, sheetVersion: (res as any).version, cells: (res as any).cells });
        nsp.to(`sheet:${sheetId}`).emit('cells:changed', { diffs: (res as any).diffs, sheetVersion: (res as any).sheetVersion });
        ack({ ok: true, sheetVersion: (res as any).sheetVersion });
      } catch (e:any) { ack({ error: 'server' }); }
    });
  });
}

