// src/hooks/useSheet.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSheetsSock(token:string){ if(sock) return sock; sock = io('/sheets',{auth:{token},transports:['websocket']}); return sock; }

type Cell = { ref:string; formula?:string; value:any; err?:string; cellVersion:number };
export function useSheet(sheetId:string, token:string) {
  const [cells, setCells] = useState<Map<string, Cell>>(new Map());
  const [sheetVersion, setSheetVersion] = useState(0);
  const [calculating, setCalculating] = useState(false);
  useEffect(() => {
    const s = getSheetsSock(token);
    const open = () => s.emit('sheet:open',{sheetId},(res:any)=>{ if(res.error) return; setCells(new Map(res.cells.map((c:Cell)=>[c.ref,c]))); setSheetVersion(res.sheet.version); });
    const onChanged = ({ diffs, sheetVersion }:any) => {
      setCells(prev => { const n = new Map(prev); for (const d of diffs) n.set(d.ref, { ...(n.get(d.ref) ?? { ref: d.ref, value: null, cellVersion: 0 }), ...d }); return n; });
      setSheetVersion(sheetVersion);
    };
    s.on('connect', open); s.on('cells:changed', onChanged);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('cells:changed', onChanged); };
  }, [sheetId, token]);
  const editCell = useCallback(async (ref:string, formula:string) => {
    setCalculating(true);
    return new Promise<any>((resolve, reject) => {
      getSheetsSock(token).emit('cell:edit', { sheetId, ref, formula, expectedSheetVersion: sheetVersion }, (res:any) => {
        setCalculating(false);
        if (res.error) return reject(new Error(res.error));
        if (res.conflict) { setCells(new Map(res.cells.map((c:Cell)=>[c.ref,c]))); setSheetVersion(res.sheetVersion); return reject(new Error('conflict_refreshed')); }
        resolve(res);
      });
    });
  }, [sheetId, token, sheetVersion]);
  return { cells: [...cells.values()], sheetVersion, calculating, editCell };
}

