const PreKeyBundleSchema = new Schema({
  _id: String, // userId:deviceId
  userId: { type: String, required: true, index: true },
  deviceId: String,
  identityKey: String,
  signedPreKey: { id: Number, key: String, signature: String, createdAt: Date },
  oneTimePreKeys: [{ id: Number, key: String }], // consumed via $pop
  registrationId: Number,
  updatedAt: { type: Date, default: Date.now },
});

const EncMessageSchema = new Schema({
  conversationId: { type: String, required: true, index: true },
  senderId: String,
  senderDeviceId: String,
  recipientId: String,
  recipientDeviceId: String,
  ciphertext: { type: Buffer, required: true },
  messageType: Number, // 1=prekey, 3=signal
  serverTs: { type: Date, default: Date.now, index: true },
  deliveredAt: Date,
  expiresAt: { type: Date, expires: 0 }, // disappearing messages TTL
});
EncMessageSchema.index({ conversationId: 1, serverTs: 1 });
EncMessageSchema.index({ recipientId: 1, recipientDeviceId: 1, deliveredAt: 1 });

