// src/routes/secureMessages.ts
import { Router } from 'express';
import { EncMessage } from '../models/EncMessage';
import { io } from '../server';
export const secureRouter = Router();
secureRouter.post('/send', async (req, res) => {
  const { conversationId, recipients } = req.body; // recipients: [{userId, deviceId, ciphertext, messageType}]
  const senderId = req.user!.id;
  const senderDeviceId = req.user!.deviceId;
  if (!Array.isArray(recipients) || recipients.length > 50) return res.status(400).json({ error: 'bad_recipients' });
  // validate recipient device ownership
  const docs = recipients.map((r:any) => ({
    conversationId, senderId, senderDeviceId, recipientId: r.userId, recipientDeviceId: r.deviceId,
    ciphertext: Buffer.from(r.ciphertext, 'base64'), messageType: r.messageType, serverTs: new Date(),
  }));
  const inserted = await EncMessage.insertMany(docs, { ordered: false });
  for (const m of inserted) {
    io.of('/secure').to(`user:${m.recipientId}:device:${m.recipientDeviceId}`).emit('msg:new', {
      id: String(m._id), conversationId, senderId, senderDeviceId,
      ciphertext: (m.ciphertext as Buffer).toString('base64'), messageType: m.messageType, serverTs: m.serverTs.getTime(),
    });
  }
  res.json({ ok: true, count: inserted.length });
});

secureRouter.get('/keys/:userId', async (req, res) => {
  const targetUserId = req.params.userId;
  const { PreKeyBundle } = require('../models/PreKeyBundle');
  const bundles = await PreKeyBundle.find({ userId: targetUserId }).lean();
  const out: any[] = [];
  for (const b of bundles) {
    // atomically consume one-time prekey
    const consumed = await PreKeyBundle.findOneAndUpdate(
      { _id: b._id, 'oneTimePreKeys.0': { $exists: true } },
      { $pop: { oneTimePreKeys: -1 } },
      { projection: { oneTimePreKeys: { $slice: 1 } }, returnDocument: 'before' },
    );
    const oneTime = consumed?.oneTimePreKeys?.[0] ?? null;
    out.push({ deviceId: b.deviceId, identityKey: b.identityKey, signedPreKey: b.signedPreKey, oneTimePreKey: oneTime, registrationId: b.registrationId });
  }
  res.json({ bundles: out });
});

// src/socket/secure.namespace.ts
import { Namespace } from 'socket.io';
import { EncMessage } from '../models/EncMessage';
import { PreKeyBundle } from '../models/PreKeyBundle';
export function registerSecureNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.use((socket, next) => {
    const { deviceId } = socket.handshake.auth as any;
    if (!deviceId) return next(new Error('no_device'));
    (socket.data as any).deviceId = deviceId;
    next();
  });
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    const deviceId = socket.data.deviceId;
    socket.on('subscribe', async (_, ack) => {
      // verify device binding
      const ok = await PreKeyBundle.exists({ _id: `${userId}:${deviceId}` });
      if (!ok) return ack({ error: 'device_not_registered' });
      await socket.join(`user:${userId}:device:${deviceId}`);
      const undelivered = await EncMessage.find({ recipientId: userId, recipientDeviceId: deviceId, deliveredAt: null }).sort({ serverTs: 1 }).limit(200).lean();
      ack({ messages: undelivered.map(m => ({ id: String(m._id), conversationId: m.conversationId, senderId: m.senderId, senderDeviceId: m.senderDeviceId, ciphertext: (m.ciphertext as Buffer).toString('base64'), messageType: m.messageType, serverTs: m.serverTs.getTime() })) });
    });
    socket.on('msg:ack', async ({ ids }) => {
      if (!Array.isArray(ids)) return;
      await EncMessage.updateMany({ _id: { $in: ids }, recipientId: userId, recipientDeviceId: deviceId, deliveredAt: null }, { $set: { deliveredAt: new Date() } });
    });
    socket.on('keys:replenish', async ({ signedPreKey, oneTimePreKeys, identityKey, registrationId }, ack) => {
      await PreKeyBundle.updateOne(
        { _id: `${userId}:${deviceId}` },
        { $set: { userId, deviceId, identityKey, signedPreKey, registrationId, updatedAt: new Date() }, $push: { oneTimePreKeys: { $each: oneTimePreKeys, $slice: -500 } } },
        { upsert: true },
      );
      ack({ ok: true });
    });
  });
}

