// src/crypto/store.ts (interfaces with libsignal-protocol-js)
import { SessionBuilder, SessionCipher, SignalProtocolStore } from '@privacyresearch/libsignal-protocol-typescript';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
export function getSecureSock(token:string, deviceId:string){ if(sock) return sock; sock = io('/secure',{auth:{token,deviceId},transports:['websocket']}); return sock; }

// src/hooks/useSecureChat.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { getSecureSock } from '../crypto/store';
export function useSecureChat(token:string, deviceId:string, store:any, myUserId:string) {
  const [messages, setMessages] = useState<{ id:string; from:string; plaintext:string; ts:number }[]>([]);
  const ackBufRef = useRef<string[]>([]);

  useEffect(() => {
    const s = getSecureSock(token, deviceId);
    const onSubscribe = () => s.emit('subscribe', {}, async (res:any) => {
      if (res.error) return;
      for (const m of res.messages) await ingest(m);
    });
    const ingest = async (m:any) => {
      try {
        const cipher = new SessionCipher(store, { name: m.senderId, deviceId: 1 });
        const plain = m.messageType === 3 ? await cipher.decryptWhisperMessage(m.ciphertext, 'base64') : await cipher.decryptPreKeyWhisperMessage(m.ciphertext, 'base64');
        const text = new TextDecoder().decode(plain);
        setMessages(prev => [...prev, { id: m.id, from: m.senderId, plaintext: text, ts: m.serverTs }]);
        ackBufRef.current.push(m.id);
      } catch (e) { console.error('decrypt_failed', e); }
    };
    const onNew = (m:any) => ingest(m);
    s.on('connect', onSubscribe);
    s.on('msg:new', onNew);
    if (s.connected) onSubscribe();
    const ackTimer = setInterval(() => {
      if (ackBufRef.current.length === 0) return;
      const ids = ackBufRef.current; ackBufRef.current = [];
      s.emit('msg:ack', { ids });
    }, 1000);
    return () => { s.off('connect', onSubscribe); s.off('msg:new', onNew); clearInterval(ackTimer); };
  }, [token, deviceId, store, myUserId]);

  const send = useCallback(async (toUserId:string, plaintext:string, conversationId:string) => {
    const bundlesResp = await fetch(`/api/keys/${toUserId}`, { headers: { authorization: `Bearer ${token}` } });
    const { bundles } = await bundlesResp.json();
    const recipients: any[] = [];
    for (const b of bundles) {
      if (!b.oneTimePreKey) continue;
      const builder = new SessionBuilder(store, { name: toUserId, deviceId: 1 });
      await builder.processPreKey({ registrationId: b.registrationId, identityKey: b.identityKey, signedPreKey: b.signedPreKey, preKey: b.oneTimePreKey });
      const cipher = new SessionCipher(store, { name: toUserId, deviceId: 1 });
      const ct = await cipher.encrypt(new TextEncoder().encode(plaintext));
      recipients.push({ userId: toUserId, deviceId: b.deviceId, ciphertext: Buffer.from(ct.body).toString('base64'), messageType: ct.type });
    }
    await fetch('/api/send', { method:'POST', headers:{'content-type':'application/json',authorization:`Bearer ${token}`}, body: JSON.stringify({ conversationId, recipients }) });
  }, [token, store]);

  return { messages, send };
}

