CREATE TABLE sli_events (
  ts TIMESTAMPTZ NOT NULL,
  service TEXT NOT NULL,
  is_error BOOLEAN NOT NULL,
  latency_ms INT NOT NULL
);
SELECT create_hypertable('sli_events','ts');
CREATE INDEX ON sli_events (service, ts DESC);

CREATE MATERIALIZED VIEW sli_1m WITH (timescaledb.continuous) AS
SELECT service, time_bucket('1 minute', ts) AS bucket, count(*) AS total, count(*) FILTER (WHERE is_error) AS errors FROM sli_events GROUP BY service, bucket;
SELECT add_continuous_aggregate_policy('sli_1m', start_offset => INTERVAL '6 hours', end_offset => INTERVAL '1 minute', schedule_interval => INTERVAL '1 minute');

CREATE TABLE slos (id BIGSERIAL PK, service TEXT, target NUMERIC, window_days INT);
CREATE TABLE alerts (id BIGSERIAL PK, service TEXT, slo_id BIGINT, burn_rate NUMERIC, opened_at TIMESTAMPTZ DEFAULT now(), closed_at TIMESTAMPTZ);

