// src/workers/burnRateCalc.ts
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { io } from '../server';
import { pageOnCall } from '../infra/pager';

export function startBurnRateLoop() {
  setInterval(async () => {
    const slos = await pool.query('SELECT id, service, target FROM slos');
    for (const slo of slos.rows) {
      const { rows } = await pool.query(`WITH win AS (SELECT sum(errors) AS e, sum(total) AS t FROM sli_1m WHERE service=$1 AND bucket > now()-interval '5 minutes') SELECT CASE WHEN t=0 OR t IS NULL THEN 0 ELSE (e::numeric/t) / (1 - $2::numeric) END AS burn_rate FROM win`, [slo.service, slo.target]);
      const burn = Number(rows[0]?.burn_rate ?? 0);
      io.of('/sli').to(`sli:${slo.service}`).emit('burn:update', { service: slo.service, burnRate: burn, ts: Date.now() });
      const key = `burn:streak:${slo.id}`;
      if (burn > 14.4) {
        const streak = await redis.incr(key);
        if (streak === 1) await redis.expire(key, 120);
        if (streak >= 2) {
          const existing = await pool.query('SELECT id FROM alerts WHERE slo_id=$1 AND closed_at IS NULL', [slo.id]);
          if (existing.rowCount === 0) {
            const ins = await pool.query('INSERT INTO alerts(service, slo_id, burn_rate) VALUES ($1,$2,$3) RETURNING id', [slo.service, slo.id, burn]);
            const alertId = ins.rows[0].id;
            try { await pageOnCall(slo.service, burn, alertId); } catch (e) { /* fallback: email */ }
            io.of('/sli').to(`sli:${slo.service}`).emit('alert:opened', { alertId, service: slo.service, burnRate: burn });
          }
        }
      } else {
        await redis.del(key);
        // close active alert if recovered for 5 min — separate sweeper job
      }
    }
  }, 30_000);
}

// src/socket/sli.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
export function registerSliNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('sli:subscribe', async ({ services }, ack) => {
      for (const s of services) await socket.join(`sli:${s}`);
      const { rows } = await pool.query(`SELECT service, bucket, total, errors FROM sli_1m WHERE service = ANY($1::text[]) AND bucket > now() - interval '1 hour' ORDER BY bucket`, [services]);
      const alerts = await pool.query(`SELECT id, service, burn_rate, opened_at FROM alerts WHERE service = ANY($1::text[]) AND closed_at IS NULL`, [services]);
      ack({ series: rows, alerts: alerts.rows });
    });
    socket.on('alert:ack', async ({ alertId }) => {
      await pool.query("INSERT INTO alert_acks(alert_id, user_id, at) VALUES ($1,$2,now()) ON CONFLICT DO NOTHING", [alertId, socket.data.user.id]);
    });
  });
}

