// src/hooks/useSloDashboard.ts
import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSliSock(t:string){ if(sock) return sock; sock = io('/sli',{auth:{token:t},transports:['websocket']}); return sock; }
export function useSloDashboard(services:string[], token:string) {
  const [series, setSeries] = useState<any[]>([]);
  const [alerts, setAlerts] = useState<any[]>([]);
  const [currentBurn, setCurrentBurn] = useState<Record<string,number>>({});
  const key = services.join(',');
  useEffect(() => {
    const s = getSliSock(token);
    const sub = () => s.emit('sli:subscribe',{services},(r:any)=>{ if(r.error) return; setSeries(r.series); setAlerts(r.alerts); });
    const onBurn = ({service, burnRate}:any) => setCurrentBurn(prev => ({ ...prev, [service]: burnRate }));
    const onAlert = (a:any) => setAlerts(prev => [a, ...prev]);
    s.on('connect', sub); s.on('burn:update', onBurn); s.on('alert:opened', onAlert);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('burn:update', onBurn); s.off('alert:opened', onAlert); };
  }, [key, token]);
  return { series, alerts, currentBurn };
}

