// src/services/cardGame.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { validateAction, applyAction } from '../game/engine';

const SPECTATOR_DELAY_MS = 3000;

export async function submitAction(matchId:number, playerId:number, action:any, expectedVersion:number) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock($1)', [matchId]);
    const m = await client.query('SELECT state, version, current_turn, p1, p2, status FROM matches WHERE id=$1 FOR UPDATE', [matchId]);
    if (!m.rows[0]) { await client.query('ROLLBACK'); return { error: 'no_match' }; }
    if (m.rows[0].status !== 'active') { await client.query('ROLLBACK'); return { error: 'match_ended' }; }
    if (m.rows[0].version !== expectedVersion) { await client.query('ROLLBACK'); return { error: 'stale_version', state: m.rows[0].state, version: m.rows[0].version }; }
    const playerSlot = playerId === m.rows[0].p1 ? 'p1' : (playerId === m.rows[0].p2 ? 'p2' : null);
    if (!playerSlot) { await client.query('ROLLBACK'); return { error: 'not_player' }; }
    if (m.rows[0].current_turn !== playerSlot) { await client.query('ROLLBACK'); return { error: 'not_your_turn' }; }
    const v = validateAction(m.rows[0].state, action, playerSlot);
    if (!v.ok) { await client.query('ROLLBACK'); return { error: 'invalid_action', reason: v.reason }; }
    const { newState, gameEnded, winner, nextTurn } = applyAction(m.rows[0].state, action, playerSlot);
    const newVersion = m.rows[0].version + 1;
    await client.query('UPDATE matches SET state=$1, version=$2, current_turn=$3, status=$4, ended_at=$5 WHERE id=$6', [newState, newVersion, nextTurn, gameEnded ? 'ended' : 'active', gameEnded ? new Date() : null, matchId]);
    await client.query('INSERT INTO actions(match_id, player_id, action, version_before, version_after) VALUES ($1,$2,$3,$4,$5)', [matchId, playerId, action, m.rows[0].version, newVersion]);
    await client.query('COMMIT');
    const update = { matchId: String(matchId), state: newState, version: newVersion, currentTurn: nextTurn, gameEnded, winner };
    io.of('/cards').to(`match:${matchId}:players`).emit('state:update', update);
    setTimeout(() => io.of('/cards').to(`match:${matchId}:spectators`).emit('state:update', update), SPECTATOR_DELAY_MS);
    return { ok: true, version: newVersion };
