// src/services/nftAuction.ts
import mongoose from 'mongoose';
import { Auction } from '../models/Auction';
import { Bid } from '../models/Bid';
import { io } from '../server';
import { transferToken } from '../chain/client';

export async function placeBid(auctionId:string, bidderId:string, amountWei:string, nonce:string, signature:string) {
  const session = await mongoose.startSession();
  try {
    let result:any;
    await session.withTransaction(async () => {
      const a = await Auction.findOneAndUpdate({ _id: auctionId, status: 'live', endsAt: { $gt: new Date() }, $expr: { $lt: [{ $toDecimal: '$currentBidWei' }, { $toDecimal: amountWei }] } }, { $set: { currentBidWei: amountWei, currentBidderId: bidderId } }, { new: true, session });
      if (!a) { result = { error: 'too_low_or_closed' }; return; }
      try {
        await Bid.create([{ auctionId, bidderId, amountWei, nonce, signature, accepted: true }], { session });
      } catch (e:any) { if (e.code === 11000) { result = { idempotent: true }; return; } throw e; }
      result = { ok: true, currentBid: amountWei };
    });
    io.of('/nft').to(`auction:${auctionId}`).emit('bid:update', { auctionId, currentBid: amountWei, currentBidderId: bidderId, ts: Date.now() });
    return result;
  } finally { await session.endSession(); }
}

export async function settleEndedAuctions() {
  const due = await Auction.find({ status: 'live', endsAt: { $lte: new Date() } }).limit(50);
  for (const a of due) {
    const locked = await Auction.findOneAndUpdate({ _id: a._id, status: 'live' }, { $set: { status: 'settling' } }, { new: true });
    if (!locked) continue;
    if (BigInt(locked.currentBidWei) < BigInt(locked.reserveWei || '0')) {
      await Auction.updateOne({ _id: a._id }, { $set: { status: 'cancelled' } });
      io.of('/nft').to(`auction:${String(a._id)}`).emit('auction:failed', { reason: 'reserve_not_met' });
      continue;
    }
    try {
      const tx = await transferToken(locked.tokenId, locked.sellerId, locked.currentBidderId!);
      await Auction.updateOne({ _id: a._id }, { $set: { status: 'settled', settlementTxHash: tx } });
      io.of('/nft').to(`auction:${String(a._id)}`).emit('auction:settled', { winner: locked.currentBidderId, tx });
    } catch (e:any) {
      const attempts = (locked.settlementAttempts ?? 0) + 1;
      await Auction.updateOne({ _id: a._id }, { $set: { settlementAttempts: attempts, status: attempts >= 5 ? 'failed' : 'live' } });
      if (attempts >= 5) io.of('/nft').to(`auction:${String(a._id)}`).emit('auction:failed', { reason: 'settlement_failed' });
    }
  }
}
setInterval(settleEndedAuctions, 10_000);

