    const onBid = (e:any) => { if (e.auctionId !== auctionId) return; setBidUpdates(p => [...p.slice(-50), e]); setAuction((a:any) => a ? { ...a, currentBidWei: e.currentBid, currentBidderId: e.currentBidderId } : a); };
    const onSettled = (e:any) => setAuction((a:any) => a ? { ...a, status: 'settled', settlementTxHash: e.tx, currentBidderId: e.winner } : a);
    s.on('connect', watch); s.on('bid:update', onBid); s.on('auction:settled', onSettled);
    if (s.connected) watch();
    return () => { s.off('connect', watch); s.off('bid:update', onBid); s.off('auction:settled', onSettled); };
  }, [auctionId, token]);
