// src/socket/geo.namespace.ts
import { Namespace } from 'socket.io';
import { redis } from '../infra/redis';
import { latLngToCell, gridDisk } from 'h3-js';
const H3_RES = 7; // ~5km hexagons

export function registerGeoNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const workerId = socket.data.user.id;
    const orgId = socket.data.user.orgId;
    let curCell: string | null = null;
    let subscribedRing: string[] = [];

    socket.on('pos:update', async ({ lat, lng, accuracy }) => {
      if (accuracy > 200) return; // bad GPS — ignore
      const cell = latLngToCell(lat, lng, H3_RES);
      const cur = await redis.hgetall(`worker:pos:${workerId}`);
      const oldCell = cur.h3;
      const pipe = redis.pipeline();
      if (oldCell && oldCell !== cell) pipe.srem(`org:${orgId}:cell:${oldCell}`, workerId);
      pipe.sadd(`org:${orgId}:cell:${cell}`, workerId);
      pipe.expire(`org:${orgId}:cell:${cell}`, 120);
      pipe.hset(`worker:pos:${workerId}`, { h3: cell, lat, lng, updatedAt: Date.now() });
      pipe.expire(`worker:pos:${workerId}`, 120);
      await pipe.exec();
      curCell = cell;
      // fan-out to subscribers of this cell
      nsp.to(`org:${orgId}:cell:${cell}`).emit('pos:peer', { workerId, lat, lng, ts: Date.now() });
    });

    socket.on('visibility:subscribe', async ({ lat, lng }, ack) => {
      const center = latLngToCell(lat, lng, H3_RES);
      const ring = gridDisk(center, 1); // ~3-5km depending on lat
      // leave old rooms
      for (const old of subscribedRing) await socket.leave(`org:${orgId}:cell:${old}`);
      for (const c of ring) await socket.join(`org:${orgId}:cell:${c}`);
      subscribedRing = ring;
      // initial roster
      const roster: any[] = [];
      for (const c of ring) {
        const ids = await redis.smembers(`org:${orgId}:cell:${c}`);
        for (const id of ids) {
          if (id === workerId) continue;
          const p = await redis.hgetall(`worker:pos:${id}`);
          if (p.lat) roster.push({ workerId: id, lat: Number(p.lat), lng: Number(p.lng), ts: Number(p.updatedAt) });
        }
      }
      ack({ roster });
    });

    socket.on('disconnect', async () => {
      const cur = await redis.hgetall(`worker:pos:${workerId}`);
      if (cur.h3) await redis.srem(`org:${orgId}:cell:${cur.h3}`, workerId);
      await redis.del(`worker:pos:${workerId}`);
    });
  });
}

