import { useEffect, useState, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getGeoSock(t:string){ if(sock) return sock; sock = io('/geo',{auth:{token:t},transports:['websocket']}); return sock; }
export function useGeoPresence(token:string) {
  const [peers, setPeers] = useState<Map<string,any>>(new Map());
  const watchIdRef = useRef<number | null>(null);
  useEffect(() => {
    const s = getGeoSock(token);
    const onPeer = (p:any) => setPeers(prev => { const n = new Map(prev); n.set(p.workerId, p); return n; });
    s.on('pos:peer', onPeer);
    let lastSub = 0;
    watchIdRef.current = navigator.geolocation.watchPosition(
      pos => {
        s.emit('pos:update', { lat: pos.coords.latitude, lng: pos.coords.longitude, accuracy: pos.coords.accuracy });
        const now = Date.now();
        if (now - lastSub > 60_000) { lastSub = now; s.emit('visibility:subscribe', { lat: pos.coords.latitude, lng: pos.coords.longitude }, (res:any) => { for (const p of res.roster) setPeers(prev => { const n = new Map(prev); n.set(p.workerId, p); return n; }); }); }
      }, undefined, { enableHighAccuracy: true, maximumAge: 5000 },
    );
    return () => { s.off('pos:peer', onPeer); if (watchIdRef.current != null) navigator.geolocation.clearWatch(watchIdRef.current); };
  }, [token]);
  return { peers: [...peers.values()] };
}

