// src/socket/whiteboard.namespace.ts
import { Namespace } from 'socket.io';
import { Stroke } from '../models/Stroke';
import { redis } from '../infra/redis';

export function registerWhiteboardNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    let boardId: string | null = null;
    socket.on('board:open', async ({ boardId: bid, viewport }, ack) => {
      if (!await canEdit(userId, bid)) return ack({ error: 'forbidden' });
      boardId = bid; await socket.join(`board:${bid}`);
      const strokes = await Stroke.find({ boardId: bid, deletedAt: null, maxX: { $gte: viewport.minX }, minX: { $lte: viewport.maxX }, maxY: { $gte: viewport.minY }, minY: { $lte: viewport.maxY } }).limit(5000).lean();
      ack({ strokes });
    });
    socket.on('stroke:start', async ({ strokeId, color, width }) => {
      if (!boardId) return;
      await redis.hset(`stroke:${boardId}:${strokeId}`, { authorId: userId, color, width, started: Date.now() });
      await redis.expire(`stroke:${boardId}:${strokeId}`, 60);
      socket.to(`board:${boardId}`).emit('peer:stroke', { type: 'start', strokeId, authorId: userId, color, width });
    });
    socket.on('stroke:point', async ({ strokeId, x, y, pressure }) => {
      if (!boardId) return;
      await redis.rpush(`stroke:${boardId}:${strokeId}:pts`, JSON.stringify([x, y, pressure ?? 1]));
      await redis.expire(`stroke:${boardId}:${strokeId}:pts`, 60);
      socket.to(`board:${boardId}`).emit('peer:stroke', { type: 'point', strokeId, x, y, pressure });
    });
    socket.on('stroke:end', async ({ strokeId, points, color, width }) => {
      if (!boardId) return;
      const xs = points.map((p:number[]) => p[0]); const ys = points.map((p:number[]) => p[1]);
      const minX = Math.min(...xs), maxX = Math.max(...xs), minY = Math.min(...ys), maxY = Math.max(...ys);
      const doc = await Stroke.create({ boardId, authorId: userId, points, color, width, minX, maxX, minY, maxY });
      await redis.del(`stroke:${boardId}:${strokeId}`); await redis.del(`stroke:${boardId}:${strokeId}:pts`);
      socket.to(`board:${boardId}`).emit('peer:stroke', { type: 'end', strokeId, finalId: String(doc._id) });
    });
    socket.on('stroke:erase', async ({ strokeIds }) => {
      if (!boardId) return;
      await Stroke.updateMany({ _id: { $in: strokeIds }, boardId }, { $set: { deletedAt: new Date() } });
      nsp.to(`board:${boardId}`).emit('peer:stroke', { type: 'erase', strokeIds });
    });
    socket.on('disconnect', async () => {
      // cleanup any in-progress strokes from Redis
      // (could scan keys with pattern; here simply rely on TTL)
    });
  });
}

