// src/hooks/useWhiteboard.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
import { v4 as uuid } from 'uuid';
let sock: Socket | null = null;
function getWbSock(t:string){ if(sock) return sock; sock = io('/whiteboard',{auth:{token:t},transports:['websocket']}); return sock; }
export function useWhiteboard(boardId:string, token:string, viewport:any) {
  const [strokes, setStrokes] = useState<any[]>([]);
  const [liveStrokes, setLiveStrokes] = useState<Map<string,any>>(new Map());
  useEffect(() => {
    const s = getWbSock(token);
    const open = () => s.emit('board:open',{boardId,viewport},(res:any)=>{ if(!res.error) setStrokes(res.strokes); });
    const onPeer = (e:any) => {
      if (e.type === 'start') setLiveStrokes(p => { const n = new Map(p); n.set(e.strokeId, { strokeId: e.strokeId, authorId: e.authorId, color: e.color, width: e.width, points: [] }); return n; });
      else if (e.type === 'point') setLiveStrokes(p => { const n = new Map(p); const cur = n.get(e.strokeId); if (cur) { cur.points = [...cur.points, [e.x, e.y, e.pressure]]; n.set(e.strokeId, cur); } return n; });
      else if (e.type === 'end') { setLiveStrokes(p => { const n = new Map(p); n.delete(e.strokeId); return n; }); /* canonical stroke fetched on next viewport update */ }
      else if (e.type === 'erase') setStrokes(p => p.filter(s => !e.strokeIds.includes(s._id)));
    };
    s.on('connect', open); s.on('peer:stroke', onPeer);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('peer:stroke', onPeer); };
  }, [boardId, token, viewport]);
  const startStroke = useCallback((color:string, width:number) => { const id = uuid(); getWbSock(token).emit('stroke:start',{strokeId:id,color,width}); return id; }, [token]);
  const addPoint = useCallback((strokeId:string, x:number, y:number, pressure=1) => { getWbSock(token).emit('stroke:point',{strokeId,x,y,pressure}); }, [token]);
  const endStroke = useCallback((strokeId:string, points:number[][], color:string, width:number) => { getWbSock(token).emit('stroke:end',{strokeId,points,color,width}); }, [token]);
  const erase = useCallback((ids:string[]) => { setStrokes(p => p.filter(s => !ids.includes(s._id))); getWbSock(token).emit('stroke:erase',{strokeIds:ids}); }, [token]);
  return { strokes, liveStrokes: [...liveStrokes.values()], startStroke, addPoint, endStroke, erase };
}

