// src/workers/digestWorker.ts
import { pool } from '../infra/pg';
import { sendEmail } from '../infra/email';
import { DateTime } from 'luxon';

export async function runDigest() {
  const { rows: users } = await pool.query(`SELECT user_id, cadence, timezone, send_window_start, send_window_end FROM digest_prefs WHERE cadence IN ('hourly','daily','weekly')`);
  for (const u of users) {
    const local = DateTime.now().setZone(u.timezone || 'UTC');
    if (u.cadence === 'hourly' && local.minute > 5) continue;
    if (u.cadence === 'daily' && local.hour !== 9) continue;
    if (u.cadence === 'weekly' && (local.weekday !== 1 || local.hour !== 9)) continue;
    if (u.send_window_start && (local.toFormat('HH:mm') < u.send_window_start || local.toFormat('HH:mm') > u.send_window_end)) continue;
    const windowEnd = local.startOf(u.cadence === 'hourly' ? 'hour' : (u.cadence === 'daily' ? 'day' : 'week')).toJSDate();
    const windowStart = DateTime.fromJSDate(windowEnd).minus({ [u.cadence === 'hourly' ? 'hours' : (u.cadence === 'daily' ? 'days' : 'weeks')]: 1 }).toJSDate();
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      const exists = await client.query('INSERT INTO digest_log(user_id, window_start, window_end, mention_count) VALUES ($1,$2,$3,$4) ON CONFLICT (user_id, window_end) DO NOTHING RETURNING id', [u.user_id, windowStart, windowEnd, 0]);
      if (exists.rowCount === 0) { await client.query('COMMIT'); continue; }
      const m = await client.query(`SELECT id, message_id FROM mentions WHERE mentioned_user_id=$1 AND created_at >= $2 AND created_at < $3 AND read_at IS NULL AND digested_at IS NULL`, [u.user_id, windowStart, windowEnd]);
      if (m.rowCount === 0) { await client.query('ROLLBACK'); continue; }
      await client.query('UPDATE digest_log SET mention_count=$1 WHERE id=$2', [m.rowCount, exists.rows[0].id]);
      await client.query('UPDATE mentions SET digested_at=now() WHERE id = ANY($1::bigint[])', [m.rows.map(r => r.id)]);
      await client.query('COMMIT');
      await sendEmail(u.user_id, `${m.rowCount} mentions in last ${u.cadence === 'hourly' ? 'hour' : u.cadence}`, m.rows);
    } catch (e) { await client.query('ROLLBACK'); console.error('digest_err', e); } finally { client.release(); }
  }
}
setInterval(runDigest, 5 * 60 * 1000);

