export async function ingestTelemetry(t: any) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query(`INSERT INTO telemetry(vehicle_id, customer_id, ts, geom, speed_kph, fuel_pct, engine_temp_c) VALUES ($1,$2,to_timestamp($3/1000.0), ST_SetSRID(ST_MakePoint($4,$5),4326),$6,$7,$8)`, [t.vehicleId, t.customerId, t.ts, t.lng, t.lat, t.speed, t.fuel, t.engineTemp]);
    // breach check: inside vs prior status
    const inside = await client.query(`SELECT g.id, g.name FROM geofences g WHERE g.customer_id=$1 AND ST_Covers(g.geom, ST_SetSRID(ST_MakePoint($2,$3),4326)::geography)`, [t.customerId, t.lng, t.lat]);
    const prevState = await client.query(`SELECT geofence_id, type FROM fence_events WHERE vehicle_id=$1 ORDER BY ts DESC LIMIT 1`, [t.vehicleId]);
    const newFences = new Set(inside.rows.map((r:any) => Number(r.id)));
    const prevFences = new Set(prevState.rows.filter((r:any) => r.type === 'enter').map((r:any) => Number(r.geofence_id)));
    for (const fid of newFences) if (!prevFences.has(fid)) await client.query(`INSERT INTO fence_events(vehicle_id, geofence_id, type) VALUES ($1,$2,'enter')`, [t.vehicleId, fid]);
    for (const fid of prevFences) if (!newFences.has(fid)) await client.query(`INSERT INTO fence_events(vehicle_id, geofence_id, type) VALUES ($1,$2,'exit')`, [t.vehicleId, fid]);
    await client.query('COMMIT');
    io.of('/fleet').to(`fleet:${t.customerId}`).emit('telemetry', { vehicleId: t.vehicleId, lat: t.lat, lng: t.lng, speed: t.speed, fuel: t.fuel, ts: t.ts });
    io.of('/fleet').to(`vehicle:${t.vehicleId}`).emit('telemetry', t);
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

