    const customerId = socket.data.user.customerId;
    socket.on('fleet:subscribe', async (_, ack) => { await socket.join(`fleet:${customerId}`); const { rows } = await pool.query(`SELECT DISTINCT ON (vehicle_id) vehicle_id, ts, ST_Y(geom) lat, ST_X(geom) lng, speed_kph FROM telemetry WHERE customer_id=$1 ORDER BY vehicle_id, ts DESC`, [customerId]); ack({ vehicles: rows }); });
    socket.on('vehicle:subscribe', async ({ vehicleId }, ack) => { await socket.join(`vehicle:${vehicleId}`); ack({ ok: true }); });
    socket.on('playback:request', async ({ vehicleId, t0, t1 }, ack) => { const { rows } = await pool.query(`SELECT ts, ST_Y(geom) lat, ST_X(geom) lng, speed_kph FROM telemetry WHERE vehicle_id=$1 AND ts BETWEEN $2 AND $3 ORDER BY ts`, [vehicleId, new Date(t0), new Date(t1)]); ack({ points: rows }); });
  });
