// src/services/recordedCall.ts
import { Call } from '../models/Call';
import { CallAudit } from '../models/CallAudit';
import { startRecording, stopRecording } from '../infra/recorder';
import { io } from '../server';
import crypto from 'crypto';

async function audit(callId:string, event:string, actorId:string, payload:any) {
  const prev = await CallAudit.findOne({ callId }).sort({ at: -1 }).select('rowHash').lean();
  const prevHash = prev?.rowHash ?? Buffer.alloc(32);
  const rowHash = crypto.createHash('sha256').update(Buffer.concat([Buffer.from(prevHash), Buffer.from(JSON.stringify({event, actorId, payload, at: Date.now()}))])).digest();
  await CallAudit.create({ callId, event, actorId, payload, prevHash, rowHash });
}

export async function grantConsent(callId:string, userId:string) {
  const call = await Call.findOneAndUpdate({ _id: callId, status: 'consenting' }, { $set: { [`consents.${userId}`]: { granted: true, at: new Date() } } }, { new: true });
  if (!call) return { error: 'invalid' };
  await audit(callId, 'consent:grant', userId, {});
  const total = call.consents?.size ?? 0; const granted = call.consents ? Array.from(call.consents.values()).filter((c:any)=>c.granted).length : 0;
  if (granted === total) {
    await Call.updateOne({ _id: callId }, { $set: { status: 'recording-ready', recordingState: 'starting' } });
    try {
      const recPath = await startRecording(callId);
      await Call.updateOne({ _id: callId }, { $set: { recordingState: 'ready', recordingPath: recPath } });
      await audit(callId, 'recording:ready', 'system', { path: recPath });
      await Call.updateOne({ _id: callId }, { $set: { status: 'live', recordingState: 'live' } });
      io.of('/secureCall').to(`call:${callId}`).emit('media:ready', { ok: true });
    } catch (e:any) {
      await Call.updateOne({ _id: callId }, { $set: { recordingState: 'failed', status: 'ended', endedAt: new Date() } });
      await audit(callId, 'recording:failed', 'system', { error: String(e) });
      io.of('/secureCall').to(`call:${callId}`).emit('recording:status', { state: 'failed' });
    }
  }
  return { ok: true };
}

export async function revokeConsent(callId:string, userId:string) {
  await audit(callId, 'consent:revoke', userId, {});
  // pause user tracks in SFU; if last consenter, end call
  await Call.updateOne({ _id: callId }, { $set: { [`consents.${userId}`]: { granted: false, at: new Date() } } });
  io.of('/secureCall').to(`call:${callId}`).emit('consent:revoked', { userId });
}

