import { Namespace } from 'socket.io';
import { Call } from '../models/Call';
import { grantConsent, revokeConsent } from '../services/recordedCall';
export function registerSecureCallNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('call:join', async ({ callId }, ack) => {
      const c = await Call.findById(callId);
      if (!c) return ack({ error: 'no_call' });
      await socket.join(`call:${callId}`);
      ack({ status: c.status, recordingState: c.recordingState });
    });
    socket.on('consent:grant', async ({ callId }, ack) => { const r = await grantConsent(callId, socket.data.user.id); ack(r); });
    socket.on('consent:revoke', async ({ callId }) => { await revokeConsent(callId, socket.data.user.id); });
  });
}

