// src/services/pollService.ts
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { io } from '../server';

export async function vote(pollId:number, fp:string, optionId:string, ip:string) {
  const ipKey = `poll:ipcap:${pollId}:${ip}`;
  const ipN = await redis.incr(ipKey);
  if (ipN === 1) await redis.expire(ipKey, 60);
  if (ipN > 30) return { error: 'rate_limited' };
  const ins = await pool.query('INSERT INTO votes(poll_id, attendee_fp, option_id, ip) VALUES ($1,$2,$3,$4) ON CONFLICT (poll_id, attendee_fp) DO NOTHING RETURNING attendee_fp', [pollId, fp, optionId, ip]);
  if (ins.rowCount === 0) return { error: 'already_voted' };
  await redis.hincrby(`poll:tally:${pollId}`, optionId, 1);
  return { ok: true };
}

// throttled fan-out per poll
const lastFan = new Map<string, number>();
export async function broadcastTally(pollId:number) {
  const key = `tally:${pollId}`;
  const now = Date.now();
  if ((lastFan.get(key) ?? 0) > now - 100) return;
  lastFan.set(key, now);
  const t = await redis.hgetall(`poll:tally:${pollId}`);
  io.of('/polls').to(`poll:${pollId}`).emit('tally', { pollId, counts: Object.fromEntries(Object.entries(t).map(([k,v])=>[k,Number(v)])) });
}

// src/socket/polls.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { vote, broadcastTally } from '../services/pollService';
export function registerPollsNamespace(nsp: Namespace) {
  nsp.use(authOrAnonMw);
  nsp.on('connection', (socket) => {
    socket.on('poll:open', async ({ pollId }, ack) => {
      const { rows } = await pool.query('SELECT id, question, options, status FROM polls WHERE id=$1', [pollId]);
      if (!rows[0]) return ack({ error: 'no_poll' });
      await socket.join(`poll:${pollId}`);
      if (socket.data.user.role === 'presenter') await socket.join(`presenter:poll:${pollId}`);
      ack({ poll: rows[0] });
    });
    socket.on('vote', async ({ pollId, optionId }, ack) => {
      const fp = socket.data.user.fp ?? socket.data.user.id;
      const ip = socket.handshake.address;
      const res = await vote(pollId, fp, optionId, ip);
      ack(res);
      if (res.ok) broadcastTally(pollId);
    });
    socket.on('reveal', async ({ pollId }, ack) => {
      if (socket.data.user.role !== 'presenter') return ack({ error: 'forbidden' });
      await pool.query("UPDATE polls SET status='revealed', revealed_at=now() WHERE id=$1", [pollId]);
      nsp.to(`poll:${pollId}`).emit('reveal', { pollId });
    });
  });
}

