let sock: Socket | null = null;
function getPollSock(t:string){ if(sock) return sock; sock = io('/polls',{auth:{token:t},transports:['websocket']}); return sock; }
export function usePoll(pollId:string, token:string) {
  const [poll, setPoll] = useState<any>(null);
  const [tally, setTally] = useState<Record<string,number>>({});
  const [voted, setVoted] = useState(false);
  useEffect(() => {
    const s = getPollSock(token);
    const open = () => s.emit('poll:open',{pollId},(r:any)=>{ if(!r.error) setPoll(r.poll); });
    const onTally = (t:any) => { if (t.pollId === pollId) setTally(t.counts); };
    s.on('connect', open); s.on('tally', onTally);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('tally', onTally); };
  }, [pollId, token]);
  const vote = useCallback((optionId:string) => new Promise((res,rej)=>getPollSock(token).emit('vote',{pollId,optionId},(r:any)=>{ if(r.error) rej(r); else { setVoted(true); res(r); } })), [pollId, token]);
  return { poll, tally, voted, vote };
}

