// src/services/saga.ts
import { pool } from '../infra/pg';
import { Queue, Worker } from 'bullmq';
import { redis } from '../infra/redis';
import { io } from '../server';
import * as steps from './sagaSteps';

const stepQ = new Queue('saga:step', { connection: redis });
const compQ = new Queue('saga:comp', { connection: redis });
const STEPS = ['payment','inventory','shipping'] as const;
const COMP: Record<string,string> = { payment: 'refund', inventory: 'release', shipping: 'cancel_shipment' };

export async function startSaga(orderId:number) {
  for (const s of STEPS) await pool.query('INSERT INTO saga_steps(order_id, step, status) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING', [orderId, s, 'pending']);
  await stepQ.add('do', { orderId, step: STEPS[0] });
}

export function startSagaWorker() {
  new Worker('saga:step', async (job:any) => {
    const { orderId, step } = job.data;
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      const r = await client.query(`UPDATE saga_steps SET status='running', attempts=attempts+1, started_at=COALESCE(started_at, now()) WHERE order_id=$1 AND step=$2 AND status IN ('pending','failed') RETURNING attempts`, [orderId, step]);
      if (r.rowCount === 0) { await client.query('ROLLBACK'); return; }
      await client.query('COMMIT');
      io.of('/orders').to(`order:${orderId}`).emit('step:update', { orderId, step, status: 'running' });
      const result = await (steps as any)[step](orderId);
      await pool.query(`UPDATE saga_steps SET status='done', result=$1, ended_at=now() WHERE order_id=$2 AND step=$3`, [result, orderId, step]);
      io.of('/orders').to(`order:${orderId}`).emit('step:update', { orderId, step, status: 'done' });
      const idx = STEPS.indexOf(step as any);
      if (idx < STEPS.length - 1) await stepQ.add('do', { orderId, step: STEPS[idx + 1] });
      else { await pool.query("UPDATE orders SET status='succeeded' WHERE id=$1", [orderId]); io.of('/orders').to(`order:${orderId}`).emit('order:final', { orderId, status: 'succeeded' }); }
    } catch (e:any) {
      await pool.query(`UPDATE saga_steps SET status='failed' WHERE order_id=$1 AND step=$2`, [orderId, step]);
      io.of('/orders').to(`order:${orderId}`).emit('step:update', { orderId, step, status: 'failed', error: String(e) });
      const r2 = await pool.query('SELECT attempts FROM saga_steps WHERE order_id=$1 AND step=$2', [orderId, step]);
      if (r2.rows[0].attempts >= 3) {
        // start compensation
        const done = await pool.query(`SELECT step FROM saga_steps WHERE order_id=$1 AND status='done' ORDER BY array_position(ARRAY['payment','inventory','shipping'], step) DESC`, [orderId]);
        for (const row of done.rows) await compQ.add('comp', { orderId, step: row.step });
        await pool.query("UPDATE orders SET status='failed' WHERE id=$1", [orderId]);
      } else throw e; // BullMQ retry with backoff
    } finally { client.release(); }
  }, { connection: redis });

  new Worker('saga:comp', async (job:any) => {
    const { orderId, step } = job.data;
    try {
      await pool.query(`UPDATE saga_steps SET status='compensating' WHERE order_id=$1 AND step=$2`, [orderId, step]);
      io.of('/orders').to(`order:${orderId}`).emit('step:update', { orderId, step, status: 'compensating' });
      const compFn = (steps as any)[COMP[step]];
      await compFn(orderId);
      await pool.query(`UPDATE saga_steps SET status='compensated' WHERE order_id=$1 AND step=$2`, [orderId, step]);
      io.of('/orders').to(`order:${orderId}`).emit('step:update', { orderId, step, status: 'compensated' });
    } catch (e:any) {
      const r = await pool.query('UPDATE saga_steps SET attempts=attempts+1 WHERE order_id=$1 AND step=$2 RETURNING attempts', [orderId, step]);
      if (r.rows[0].attempts >= 5) {
        await pool.query('UPDATE orders SET intervention_required=true WHERE id=$1', [orderId]);
        io.of('/orders').to(`order:${orderId}`).emit('order:final', { orderId, status: 'intervention' });
      } else throw e;
    }
  }, { connection: redis });
}

// src/socket/ordersSaga.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
export function registerOrdersSagaNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('order:subscribe', async ({ orderId }, ack) => {
      const { rows } = await pool.query('SELECT id, user_id, status, intervention_required FROM orders WHERE id=$1', [orderId]);
      if (!rows[0] || Number(rows[0].user_id) !== socket.data.user.id) return ack({ error: 'forbidden' });
      await socket.join(`order:${orderId}`);
      const steps = await pool.query('SELECT step, status, attempts FROM saga_steps WHERE order_id=$1', [orderId]);
      ack({ order: rows[0], steps: steps.rows });
    });
  });
}

