import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/orders',{auth:{token:t},transports:['websocket']}); return sock; }
export function useOrderSaga(orderId:string, token:string) {
  const [order, setOrder] = useState<any>(null);
  const [steps, setSteps] = useState<any[]>([]);
  useEffect(() => {
    const s = getSock(token);
    const sub = () => s.emit('order:subscribe',{orderId},(r:any)=>{ if(r.error) return; setOrder(r.order); setSteps(r.steps); });
    const onStep = (e:any) => { if (e.orderId !== orderId) return; setSteps(prev => prev.map(p => p.step === e.step ? { ...p, status: e.status } : p)); };
    const onFinal = (e:any) => { if (e.orderId !== orderId) return; setOrder((o:any) => ({ ...o, status: e.status })); };
    s.on('connect', sub); s.on('step:update', onStep); s.on('order:final', onFinal);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('step:update', onStep); s.off('order:final', onFinal); };
  }, [orderId, token]);
  return { order, steps };
}

