// src/socket/reviews.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { enqueueNotification } from '../services/notificationService';
export function registerReviewsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('pr:open', async ({ prId }, ack) => {
      if (!await canViewPr(userId, prId)) return ack({ error: 'forbidden' });
      await socket.join(`pr:${prId}`);
      const t = await pool.query('SELECT id, file_path, line, commit_sha, resolved FROM pr_threads WHERE pr_id=$1', [prId]);
      const c = await pool.query('SELECT id, thread_id, author_id, body, created_at FROM pr_comments WHERE thread_id = ANY($1::bigint[]) ORDER BY id', [t.rows.map(r => r.id)]);
      ack({ threads: t.rows, comments: c.rows });
    });
    socket.on('thread:create', async ({ prId, filePath, line, commitSha, hunkContext, body }, ack) => {
      const client = await pool.connect();
      try {
        await client.query('BEGIN');
        const t = await client.query('INSERT INTO pr_threads(pr_id, file_path, line, commit_sha, hunk_context) VALUES ($1,$2,$3,$4,$5) RETURNING id', [prId, filePath, line, commitSha, hunkContext]);
        const c = await client.query('INSERT INTO pr_comments(thread_id, author_id, body) VALUES ($1,$2,$3) RETURNING id, created_at', [t.rows[0].id, userId, body]);
        await client.query('COMMIT');
        const thread = { id: String(t.rows[0].id), pr_id: prId, file_path: filePath, line, commit_sha: commitSha, resolved: false };
        const comment = { id: String(c.rows[0].id), thread_id: String(t.rows[0].id), author_id: userId, body, created_at: c.rows[0].created_at };
        nsp.to(`pr:${prId}`).emit('thread:new', { thread, firstComment: comment });
        // mentions
        for (const uid of parseMentions(body)) await enqueueNotification(String(uid), { type: 'pr_mention', targetType: 'comment', targetId: comment.id, actorId: String(userId), body: 'You were mentioned in a code review' });
        ack({ thread, comment });
      } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
    });
    socket.on('comment:add', async ({ threadId, body }, ack) => {
      const r = await pool.query('SELECT t.pr_id FROM pr_threads t WHERE t.id=$1', [threadId]);
      if (!r.rows[0]) return ack({ error: 'no_thread' });
      const c = await pool.query('INSERT INTO pr_comments(thread_id, author_id, body) VALUES ($1,$2,$3) RETURNING id, created_at', [threadId, userId, body]);
      const comment = { id: String(c.rows[0].id), thread_id: String(threadId), author_id: userId, body, created_at: c.rows[0].created_at };
      nsp.to(`pr:${r.rows[0].pr_id}`).emit('comment:new', { comment });
      ack({ comment });
    });
    socket.on('thread:resolve', async ({ threadId }, ack) => {
      const r = await pool.query('UPDATE pr_threads SET resolved=true, resolved_by=$1, resolved_at=now() WHERE id=$2 AND NOT resolved RETURNING pr_id', [userId, threadId]);
      if (r.rowCount === 0) return ack({ error: 'already_resolved' });
      nsp.to(`pr:${r.rows[0].pr_id}`).emit('thread:resolved', { threadId: String(threadId), by: userId });
      ack({ ok: true });
    });
  });
}
function parseMentions(body:string){ return Array.from(body.matchAll(/@(\d+)/g)).map(m=>Number(m[1])); }

