// src/hooks/usePrReview.ts
import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/reviews',{auth:{token:t},transports:['websocket']}); return sock; }
export function usePrReview(prId:string, token:string) {
  const [threads, setThreads] = useState<any[]>([]);
  const [comments, setComments] = useState<any[]>([]);
  useEffect(() => {
    const s = getSock(token);
    const open = () => s.emit('pr:open',{prId},(r:any)=>{ if(r.error) return; setThreads(r.threads); setComments(r.comments); });
    const onThread = ({thread, firstComment}:any) => { setThreads(p => p.find(x=>x.id===thread.id) ? p : [...p, thread]); setComments(p => [...p, firstComment]); };
    const onComment = ({comment}:any) => setComments(p => p.find(x=>x.id===comment.id) ? p : [...p, comment]);
    const onResolved = ({threadId, by}:any) => setThreads(p => p.map(t => t.id === threadId ? { ...t, resolved: true, resolved_by: by } : t));
    s.on('connect', open); s.on('thread:new', onThread); s.on('comment:new', onComment); s.on('thread:resolved', onResolved);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('thread:new', onThread); s.off('comment:new', onComment); s.off('thread:resolved', onResolved); };
  }, [prId, token]);
  const createThread = useCallback((args:any) => new Promise((res,rej)=>getSock(token).emit('thread:create',{prId,...args},(r:any)=>r.error?rej(r):res(r))), [prId, token]);
  const addComment = useCallback((threadId:string, body:string) => new Promise((res,rej)=>getSock(token).emit('comment:add',{threadId,body},(r:any)=>r.error?rej(r):res(r))), [token]);
  const resolve = useCallback((threadId:string) => new Promise((res,rej)=>getSock(token).emit('thread:resolve',{threadId},(r:any)=>r.error?rej(r):res(r))), [token]);
  return { threads, comments, createThread, addComment, resolve };
}

