// src/socket/voice.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { VoiceMessage } from '../models/VoiceMessage';
import { SegmentReaction } from '../models/SegmentReaction';
import { io } from '../server';
export function registerVoiceNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.join(`user:${userId}`);
    socket.on('conv:open', async ({ convoId }, ack) => {
      await socket.join(`conv:${convoId}`);
      const msgs = await VoiceMessage.find({ convoId, deletedAt: null }).sort({ createdAt: 1 }).limit(100).lean();
      const ids = msgs.map(m => String(m._id));
      const reactions = await SegmentReaction.find({ messageId: { $in: ids } }).lean();
      const playback = await pool.query('SELECT message_id, position_ms, listened FROM playback_state WHERE user_id=$1 AND message_id = ANY($2::text[])', [userId, ids]);
      ack({ messages: msgs, reactions, playback: playback.rows });
    });
    socket.on('playback:position', async ({ messageId, positionMs, listened }) => {
      await pool.query('INSERT INTO playback_state(user_id, message_id, position_ms, listened) VALUES ($1,$2,$3,$4) ON CONFLICT (user_id, message_id) DO UPDATE SET position_ms=EXCLUDED.position_ms, listened=playback_state.listened OR EXCLUDED.listened, updated_at=now()', [userId, messageId, positionMs, !!listened]);
      socket.to(`user:${userId}`).emit('playback:synced', { messageId, positionMs, listened });
    });
    socket.on('react:segment', async ({ messageId, atMs, emoji }, ack) => {
      const r = await SegmentReaction.create({ messageId, userId, atMs, emoji });
      const msg = await VoiceMessage.findById(messageId).lean();
      if (msg) nsp.to(`conv:${msg.convoId}`).emit('segment:reaction', { messageId, userId, atMs, emoji });
      ack({ ok: true });
    });
  });
}

