// src/hooks/useVoiceChat.ts
import { useEffect, useState, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/voice',{auth:{token:t},transports:['websocket']}); return sock; }
export function useVoiceChat(convoId:string, token:string) {
  const [messages, setMessages] = useState<any[]>([]);
  const [reactions, setReactions] = useState<any[]>([]);
  const [playback, setPlayback] = useState<Record<string,{positionMs:number;listened:boolean}>>({});
  useEffect(() => {
    const s = getSock(token);
    const open = () => s.emit('conv:open',{convoId},(r:any)=>{ setMessages(r.messages); setReactions(r.reactions); setPlayback(Object.fromEntries(r.playback.map((p:any)=>[p.message_id,{positionMs:p.position_ms,listened:p.listened}]))); });
    const onMsg = (m:any) => setMessages(p => [...p, m]);
    const onReact = (r:any) => setReactions(p => [...p, r]);
    const onSynced = ({messageId, positionMs, listened}:any) => setPlayback(p => ({ ...p, [messageId]: { positionMs, listened } }));
    s.on('connect', open); s.on('msg:voice', onMsg); s.on('segment:reaction', onReact); s.on('playback:synced', onSynced);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('msg:voice', onMsg); s.off('segment:reaction', onReact); s.off('playback:synced', onSynced); };
  }, [convoId, token]);
  const updatePosition = useCallback((messageId:string, positionMs:number, listened:boolean) => getSock(token).emit('playback:position',{messageId,positionMs,listened}), [token]);
  const reactSegment = useCallback((messageId:string, atMs:number, emoji:string) => new Promise((res)=>getSock(token).emit('react:segment',{messageId,atMs,emoji},res)), [token]);
  return { messages, reactions, playback, updatePosition, reactSegment };
}

