// src/socket/incidents.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { Queue } from 'bullmq';
import { redis } from '../infra/redis';
import { Client } from 'pg';
import { io } from '../server';
const escalateQ = new Queue('escalate', { connection: redis });

const listener = new Client({ connectionString: process.env.DATABASE_URL });
export async function startIncListener() {
  await listener.connect();
  listener.on('notification', async (n) => {
    if (!n.channel.startsWith('inc_')) return;
    const incId = n.channel.slice(4);
    const { rows } = await pool.query('SELECT id, event_type, actor_id, payload, ts FROM incident_events WHERE id=$1', [n.payload]);
    if (rows[0]) io.of('/incidents').to(`inc:${incId}`).emit('event:new', rows[0]);
  });
}

export function registerIncidentsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('inc:open', async ({ incidentId }, ack) => {
      await socket.join(`inc:${incidentId}`);
      await listener.query(`LISTEN inc_${incidentId}`);
      const events = await pool.query('SELECT id, event_type, actor_id, payload, ts FROM incident_events WHERE incident_id=$1 ORDER BY id DESC LIMIT 500', [incidentId]);
      const acks = await pool.query('SELECT alert_id, user_id, acked_at FROM incident_acks WHERE incident_id=$1', [incidentId]);
      ack({ events: events.rows.reverse(), acks: acks.rows });
    });
    socket.on('comment', async ({ incidentId, body }) => {
      await pool.query(`INSERT INTO incident_events(incident_id, event_type, actor_id, payload) VALUES ($1,'comment',$2,$3)`, [incidentId, userId, { body }]);
    });
    socket.on('ack', async ({ incidentId, alertId }, ackCb) => {
      const r = await pool.query('INSERT INTO incident_acks(incident_id, alert_id, user_id) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING RETURNING acked_at', [incidentId, alertId, userId]);
      if (r.rowCount! > 0) {
        try { await escalateQ.remove(`esc:${incidentId}:${alertId}`); } catch {}
        await pool.query(`INSERT INTO incident_events(incident_id, event_type, actor_id, payload) VALUES ($1,'ack',$2,$3)`, [incidentId, userId, { alertId }]);
      }
      ackCb({ ok: true });
    });
  });
}

export async function fireAlert(incidentId:number, alertId:number) {
  await pool.query(`INSERT INTO incident_events(incident_id, event_type, payload) VALUES ($1,'alert_fired',$2)`, [incidentId, { alertId }]);
  await escalateQ.add('esc', { incidentId, alertId }, { delay: 5*60*1000, jobId: `esc:${incidentId}:${alertId}` });
}

