// src/services/brLobby.ts
import { Lobby } from '../models/Lobby';
import { io } from '../server';

export async function joinLobby(lobbyId:string, userId:string) {
  const lobby = await Lobby.findOneAndUpdate({ _id: lobbyId, status: { $in: ['waiting','countdown'] }, $expr: { $lt: [{ $size: '$players' }, '$capacity'] }, 'players.userId': { $ne: userId } }, { $push: { players: { userId, joinedAt: new Date(), ready: false } } }, { new: true });
  if (!lobby) return { error: 'cannot_join' };
  io.of('/br').to(`lobby:${lobbyId}`).emit('lobby:state', { lobby });
  if (lobby.players.length >= lobby.minPlayers && lobby.status === 'waiting') await startCountdown(lobbyId);
  return { ok: true, lobby };
}

export async function startCountdown(lobbyId:string) {
  await Lobby.updateOne({ _id: lobbyId, status: 'waiting' }, { $set: { status: 'countdown', countdownStartedAt: new Date() } });
  io.of('/br').to(`lobby:${lobbyId}`).emit('lobby:state', { lobby: await Lobby.findById(lobbyId).lean() });
}

export function startCountdownTicker() {
  setInterval(async () => {
    const lobbies = await Lobby.find({ status: 'countdown' }).lean();
    for (const l of lobbies) {
      const elapsed = (Date.now() - new Date(l.countdownStartedAt!).getTime()) / 1000;
      const remaining = Math.max(0, l.countdownSeconds - Math.floor(elapsed));
      io.of('/br').to(`lobby:${l._id}`).emit('tick', { lobbyId: l._id, remaining, serverTs: Date.now() });
      if (remaining === 0) {
        if (l.players.length < l.minPlayers) {
          await Lobby.updateOne({ _id: l._id }, { $set: { status: 'cancelled' } });
          io.of('/br').to(`lobby:${l._id}`).emit('lobby:state', { lobby: { ...l, status: 'cancelled' } });
        } else {
          await Lobby.updateOne({ _id: l._id }, { $set: { status: 'starting' } });
          const gameServer = await provisionGameServer(String(l._id));
          await Lobby.updateOne({ _id: l._id }, { $set: { status: 'started', gameServerId: gameServer.id } });
          io.of('/br').to(`lobby:${l._id}`).emit('game:start', { gameServer });
        }
      }
    }
  }, 1000);
}
async function provisionGameServer(lobbyId:string){ return { id: `gs-${lobbyId}`, host:'br.region', port: 9999, token: 'sig' }; }

// src/socket/br.namespace.ts
import { Namespace } from 'socket.io';
import { Lobby } from '../models/Lobby';
import { joinLobby } from '../services/brLobby';
export function registerBrNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('lobby:join', async ({ lobbyId }, ack) => { await socket.join(`lobby:${lobbyId}`); const r = await joinLobby(lobbyId, userId); ack(r); });
    socket.on('lobby:ready', async ({ lobbyId }, ack) => { await Lobby.updateOne({ _id: lobbyId, 'players.userId': userId }, { $set: { 'players.$.ready': true } }); ack({ ok: true }); });
    socket.on('lobby:leave', async ({ lobbyId }) => { await Lobby.updateOne({ _id: lobbyId }, { $pull: { players: { userId } } }); await socket.leave(`lobby:${lobbyId}`); });
    socket.on('disconnect', async () => { /* find lobbies this user is in and remove */ });
  });
}

