// src/hooks/useBrLobby.ts
import { useEffect, useState, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/br',{auth:{token:t},transports:['websocket']}); return sock; }
export function useBrLobby(lobbyId:string, token:string) {
  const [lobby, setLobby] = useState<any>(null);
  const [remaining, setRemaining] = useState<number | null>(null);
  const clockOffsetRef = useRef(0);
  const [gameServer, setGameServer] = useState<any>(null);
  useEffect(() => {
    const s = getSock(token);
    const onState = ({lobby}:any) => setLobby(lobby);
    const onTick = ({remaining, serverTs}:any) => { clockOffsetRef.current = serverTs - Date.now(); setRemaining(remaining); };
    const onStart = ({gameServer}:any) => setGameServer(gameServer);
    const join = () => s.emit('lobby:join',{lobbyId},(r:any)=>{ if(r.lobby) setLobby(r.lobby); });
    s.on('connect', join); s.on('lobby:state', onState); s.on('tick', onTick); s.on('game:start', onStart);
    if (s.connected) join();
    return () => { s.off('connect', join); s.off('lobby:state', onState); s.off('tick', onTick); s.off('game:start', onStart); s.emit('lobby:leave',{lobbyId}); };
  }, [lobbyId, token]);
  return { lobby, remaining, gameServer };
}

