// src/services/negotiate.ts
import { pool } from '../infra/pg';
import { Queue } from 'bullmq';
import { redis } from '../infra/redis';
import { io } from '../server';
const timerQ = new Queue('neg:timer', { connection: redis });

export async function counterOffer(negId:number, userId:number, priceCents:number) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const r = await client.query('SELECT status, current_turn, current_round, buyer_id, seller_id FROM negotiations WHERE id=$1 FOR UPDATE', [negId]);
    if (!r.rows[0] || r.rows[0].status !== 'active') { await client.query('ROLLBACK'); return { error: 'inactive' }; }
    const expected = r.rows[0].current_turn === 'buyer' ? Number(r.rows[0].buyer_id) : Number(r.rows[0].seller_id);
    if (expected !== userId) { await client.query('ROLLBACK'); return { error: 'not_your_turn' }; }
    if (r.rows[0].current_round >= 3) { await client.query('ROLLBACK'); return { error: 'max_rounds' }; }
    const nextTurn = r.rows[0].current_turn === 'buyer' ? 'seller' : 'buyer';
    const expires = new Date(Date.now() + 30*60*1000);
    await client.query(`UPDATE negotiations SET current_turn=$1, current_round=current_round+1, expires_at=$2 WHERE id=$3`, [nextTurn, expires, negId]);
    await client.query(`INSERT INTO negotiation_events(neg_id, actor_id, type, payload) VALUES ($1,$2,$3,$4)`, [negId, userId, 'counter', { priceCents }]);
    await client.query('COMMIT');
    try { await timerQ.remove(`neg:timer:${negId}`); } catch {}
    await timerQ.add('expire', { negId }, { delay: 30*60*1000, jobId: `neg:timer:${negId}` });
    io.of('/negotiate').to(`neg:${negId}`).emit('event', { type: 'counter', priceCents, by: userId });
    io.of('/negotiate').to(`neg:${negId}`).emit('state:update', { currentTurn: nextTurn, expiresAt: expires.getTime() });
    return { ok: true };
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

export function startTimerWorker() {
  const { Worker } = require('bullmq');
  new Worker('neg:timer', async (job:any) => {
    const { negId } = job.data;
    const r = await pool.query("UPDATE negotiations SET status='expired', ended_at=now() WHERE id=$1 AND status='active' RETURNING current_turn", [negId]);
    if (r.rowCount! > 0) { await pool.query(`INSERT INTO negotiation_events(neg_id, type, payload) VALUES ($1,$2,$3)`, [negId, 'expired', { failedTurn: r.rows[0].current_turn }]); io.of('/negotiate').to(`neg:${negId}`).emit('state:update', { status: 'expired' }); }
  }, { connection: redis });
}

// src/socket/negotiate.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { counterOffer } from '../services/negotiate';
export function registerNegotiateNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('neg:subscribe', async ({ negId }, ack) => {
      const r = await pool.query('SELECT id, buyer_id, seller_id, status, current_turn, current_round, expires_at FROM negotiations WHERE id=$1', [negId]);
      if (!r.rows[0] || (Number(r.rows[0].buyer_id) !== userId && Number(r.rows[0].seller_id) !== userId)) return ack({ error: 'forbidden' });
      await socket.join(`neg:${negId}`);
      const events = await pool.query('SELECT id, actor_id, type, payload, ts FROM negotiation_events WHERE neg_id=$1 ORDER BY id', [negId]);
      ack({ neg: r.rows[0], events: events.rows });
    });
    socket.on('offer:counter', async ({ negId, priceCents }, ack) => { const r = await counterOffer(negId, userId, priceCents); ack(r); });
    socket.on('chat:msg', async ({ negId, body }) => {
      const ev = await pool.query(`INSERT INTO negotiation_events(neg_id, actor_id, type, payload) VALUES ($1,$2,'chat',$3) RETURNING id, ts`, [negId, userId, { body }]);
      io.of('/negotiate').to(`neg:${negId}`).emit('event', { id: String(ev.rows[0].id), type: 'chat', body, by: userId, ts: ev.rows[0].ts });
    });
  });
}

