// src/socket/forum.namespace.ts
import { Namespace } from 'socket.io';
import { redis } from '../infra/redis';
import { io } from '../server';
const activeThreads = new Set<string>();

export function registerForumNamespace(nsp: Namespace) {
  nsp.use(authOrAnonMw);
  nsp.on('connection', (socket) => {
    let viewing: Set<string> = new Set();
    socket.on('thread:view', async ({ threadId }) => {
      await redis.sadd(`viewers:thread:${threadId}`, socket.id);
      await redis.expire(`viewers:thread:${threadId}`, 600);
      await socket.join(`thread:${threadId}`);
      viewing.add(threadId); activeThreads.add(threadId);
    });
    socket.on('thread:leave', async ({ threadId }) => {
      await redis.srem(`viewers:thread:${threadId}`, socket.id);
      await socket.leave(`thread:${threadId}`);
      viewing.delete(threadId);
    });
    socket.on('disconnect', async () => {
      for (const t of viewing) await redis.srem(`viewers:thread:${t}`, socket.id);
    });
  });
  setInterval(async () => {
    for (const t of activeThreads) {
      const n = await redis.scard(`viewers:thread:${t}`);
      if (n === 0) { activeThreads.delete(t); continue; }
      io.of('/forum').to(`thread:${t}`).emit('viewer:count', { threadId: t, count: n });
    }
  }, 5000);
}

