// src/hooks/useThreadViewers.ts
import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/forum',{auth:{token:t},transports:['websocket']}); return sock; }
export function useThreadViewers(threadId:string, token:string) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    const s = getSock(token);
    let active = !document.hidden;
    const send = (active ? 'thread:view' : 'thread:leave');
    if (active) s.emit('thread:view',{threadId});
    const onCount = (e:any) => { if (e.threadId === threadId) setCount(e.count); };
    s.on('viewer:count', onCount);
    const onVis = () => { if (document.hidden) s.emit('thread:leave',{threadId}); else s.emit('thread:view',{threadId}); };
    document.addEventListener('visibilitychange', onVis);
    return () => { s.off('viewer:count', onCount); document.removeEventListener('visibilitychange', onVis); s.emit('thread:leave',{threadId}); };
  }, [threadId, token]);
  return { count };
