// src/services/codeNotes.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { enqueueNotification } from '../services/notificationService';
import { remapNote } from '../infra/git';

export async function addNote(input:{repo:string;filePath:string;sha:string;line:number;authorId:string;body:string;}) {
  const r = await pool.query(`INSERT INTO code_notes(repo,file_path,anchor_sha,line,author_id,body,current_path,current_line) VALUES ($1,$2,$3,$4,$5,$6,$2,$4) RETURNING id`, [input.repo, input.filePath, input.sha, input.line, input.authorId, input.body]);
  const note = { id: String(r.rows[0].id), ...input, currentPath: input.filePath, currentLine: input.line };
  io.of('/codeNotes').to(`file:${input.repo}:${input.filePath}`).emit('note:added', note);
  return note;
}

export async function resolveNote(noteId:number, userId:string) {
  const r = await pool.query('UPDATE code_notes SET resolved_at=now(), resolved_by=$1 WHERE id=$2 AND resolved_at IS NULL RETURNING repo, current_path, current_line, author_id', [userId, noteId]);
  if (r.rowCount === 0) return { error: 'already_resolved' };
  io.of('/codeNotes').to(`file:${r.rows[0].repo}:${r.rows[0].current_path}`).emit('note:resolved', { id: String(noteId), by: userId });
  if (String(r.rows[0].author_id) !== userId) await enqueueNotification(String(r.rows[0].author_id), { type: 'note_resolved', targetType: 'code_note', targetId: String(noteId), actorId: userId, body: 'Your code note was resolved' });
  return { ok: true };
}

export async function refactorRemap(repo:string, oldSha:string, newSha:string) {
  const { rows } = await pool.query(`SELECT id, current_path, current_line FROM code_notes WHERE repo=$1 AND resolved_at IS NULL`, [repo]);
  for (const n of rows) {
    const remapped = await remapNote(repo, oldSha, newSha, n.current_path, n.current_line);
    if (remapped) await pool.query('UPDATE code_notes SET current_path=$1, current_line=$2 WHERE id=$3', [remapped.path, remapped.line, n.id]);
  }
}

