// src/services/pushDispatch.ts
import { pool } from '../infra/pg';
import { PushEvent } from '../models/PushEvent';
import { sendFcm, sendApns } from '../infra/pushProviders';
import { v4 as uuid } from 'uuid';

export async function dispatchPush(userId:string, payload:any) {
  const { rows } = await pool.query('SELECT id, platform, push_token FROM devices WHERE user_id=$1 AND push_token IS NOT NULL', [userId]);
  for (const d of rows) {
    const pushId = uuid();
    await PushEvent.create({ pushId, userId, deviceId: String(d.id), payload, dispatchedAt: new Date() });
    try {
      if (d.platform === 'ios') await sendApns(d.push_token, { ...payload, pushId });
      else await sendFcm(d.push_token, { ...payload, pushId });
      await PushEvent.updateOne({ pushId }, { $set: { deliveredAt: new Date() } });
    } catch (e:any) {
      await PushEvent.updateOne({ pushId }, { $set: { errorCode: e.code || 'unknown' } });
      if (e.code === 'INVALID_TOKEN') await pool.query('UPDATE devices SET push_token=NULL WHERE id=$1', [d.id]);
    }
  }
}

