// src/socket/home.namespace.ts
import { Namespace } from 'socket.io';
import { Device } from '../models/Device';
import { pool } from '../infra/pg';
import { io } from '../server';
import { v4 as uuid } from 'uuid';

export function registerHomeNamespace(nsp: Namespace) {
  nsp.use(authMw); // accepts JWT or device cert
  nsp.on('connection', (socket) => {
    const isDevice = !!(socket.data as any).deviceId;
    if (isDevice) registerDeviceHandlers(socket); else registerAppHandlers(socket);
  });
  function registerDeviceHandlers(socket:any) {
    const deviceId = socket.data.deviceId;
    socket.join(`device:${deviceId}`);
    socket.on('device:announce', async ({ homeId, type, firmwareVer }) => {
      await Device.updateOne({ _id: deviceId }, { $set: { homeId, type, firmwareVer, lastSeen: new Date() } }, { upsert: true });
      // flush queued commands
      const { rows } = await pool.query('SELECT id, command FROM device_commands WHERE device_id=$1 AND delivered_at IS NULL ORDER BY id', [deviceId]);
      for (const r of rows) { socket.emit('cmd:exec', { cmdId: r.id, ...r.command }); await pool.query('UPDATE device_commands SET delivered_at=now() WHERE id=$1', [r.id]); }
    });
    socket.on('state:update', async (patch:any) => {
      const d = await Device.findOneAndUpdate({ _id: deviceId }, { $set: { state: { ...patch }, lastSeen: new Date() } }, { new: true });
      if (d) io.of('/home').to(`home:${d.homeId}`).emit('device:state', { deviceId, state: d.state });
    });
    socket.on('cmd:ack', async ({ cmdId, success, error }) => {
      await pool.query('UPDATE device_commands SET acked_at=now() WHERE id=$1', [cmdId]);
      if (!success) console.error('cmd_failed', { cmdId, error });
    });
  }
  function registerAppHandlers(socket:any) {
    const userId = socket.data.user.id;
    socket.on('home:subscribe', async ({ homeId }, ack) => {
      if (!await isMember(userId, homeId)) return ack({ error: 'forbidden' });
      await socket.join(`home:${homeId}`);
      const devices = await Device.find({ homeId }).lean();
      ack({ devices });
    });
    socket.on('cmd:send', async ({ deviceId, command, idempotencyKey }, ack) => {
      idempotencyKey = idempotencyKey || uuid();
      const r = await pool.query('INSERT INTO device_commands(device_id, idempotency_key, command) VALUES ($1,$2,$3) ON CONFLICT (device_id, idempotency_key) DO NOTHING RETURNING id', [deviceId, idempotencyKey, command]);
      if (r.rowCount === 0) return ack({ idempotent: true });
      const sockets = await nsp.in(`device:${deviceId}`).fetchSockets();
      if (sockets.length > 0) { sockets[0].emit('cmd:exec', { cmdId: r.rows[0].id, ...command }); await pool.query('UPDATE device_commands SET delivered_at=now() WHERE id=$1', [r.rows[0].id]); }
      ack({ cmdId: r.rows[0].id, queued: sockets.length === 0 });
    });
  }
}

