// src/socket/diagrams.namespace.ts
import { Namespace } from 'socket.io';
import { Shape } from '../models/Shape';
import { Edge } from '../models/Edge';
import { redis } from '../infra/redis';
import mongoose from 'mongoose';

export function registerDiagramsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('diagram:open', async ({ diagramId }, ack) => {
      await socket.join(`diagram:${diagramId}`);
      const shapes = await Shape.find({ diagramId, deletedAt: null }).lean();
      const edges = await Edge.find({ diagramId }).lean();
      ack({ shapes, edges });
    });
    socket.on('shape:move', ({ diagramId, shapeId, x, y }) => {
      socket.to(`diagram:${diagramId}`).emit('shape:moved', { shapeId, x, y, by: userId });
    });
    socket.on('shape:save', async ({ diagramId, shapeId, x, y, expectedVersion }, ack) => {
      const r = await Shape.findOneAndUpdate({ _id: shapeId, diagramId, version: expectedVersion }, { $set: { x, y }, $inc: { version: 1 } }, { new: true });
      if (!r) return ack({ error: 'conflict' });
      ack({ version: r.version });
    });
    socket.on('shape:lock', async ({ diagramId, shapeId }, ack) => {
      const ok = await redis.set(`diag:lock:${diagramId}:${shapeId}`, userId, 'NX', 'EX', 300);
      if (!ok) return ack({ ok: false, lockedBy: await redis.get(`diag:lock:${diagramId}:${shapeId}`) });
      socket.to(`diagram:${diagramId}`).emit('shape:locked', { shapeId, by: userId });
      ack({ ok: true });
    });
    socket.on('shape:edit', async ({ diagramId, shapeId, patch, expectedVersion }, ack) => {
      const owner = await redis.get(`diag:lock:${diagramId}:${shapeId}`);
      if (owner !== userId) return ack({ error: 'not_locked' });
      const r = await Shape.findOneAndUpdate({ _id: shapeId, version: expectedVersion }, { $set: patch, $inc: { version: 1 } }, { new: true });
      if (!r) return ack({ error: 'conflict' });
      socket.to(`diagram:${diagramId}`).emit('shape:edited', { shapeId, patch, version: r.version });
      ack({ version: r.version });
    });
    socket.on('shape:delete', async ({ diagramId, shapeId }, ack) => {
      const session = await mongoose.startSession();
      try {
        await session.withTransaction(async () => {
          await Shape.updateOne({ _id: shapeId, diagramId }, { $set: { deletedAt: new Date() } }, { session });
          await Edge.deleteMany({ diagramId, $or: [{ fromShapeId: shapeId }, { toShapeId: shapeId }] }, { session });
        });
        nsp.to(`diagram:${diagramId}`).emit('shape:deleted', { shapeId });
        ack({ ok: true });
      } finally { await session.endSession(); }
    });
  });
}

