// src/services/importJob.ts
import { pool } from '../infra/pg';
import { io } from '../server';
import { Worker, Queue } from 'bullmq';
import { redis } from '../infra/redis';
import { parse } from 'csv-parse';
import fs from 'fs';

const importQ = new Queue('imports', { connection: redis });

export async function startImport(userId:number, filePath:string, fileHash:string) {
  const r = await pool.query('INSERT INTO imports(user_id, file_hash, status) VALUES ($1,$2,$3) ON CONFLICT (user_id, file_hash) DO UPDATE SET status=imports.status RETURNING id, status, last_processed_row', [userId, fileHash, 'queued']);
  await importQ.add('run', { importId: String(r.rows[0].id), filePath });
  return { importId: String(r.rows[0].id), resumeFrom: r.rows[0].last_processed_row };
}

export function startImportWorker() {
  new Worker('imports', async (job:any) => {
    const { importId, filePath } = job.data;
    const i = await pool.query('SELECT id, last_processed_row, status FROM imports WHERE id=$1', [importId]);
    if (!i.rows[0] || i.rows[0].status === 'cancelled') return;
    await pool.query("UPDATE imports SET status='running' WHERE id=$1", [importId]);
    const startFrom = i.rows[0].last_processed_row;
    const parser = fs.createReadStream(filePath).pipe(parse({ columns: true, from_line: startFrom + 1 }));
    let row = startFrom;
    let batch: any[] = [];
    const flush = async () => {
      if (!batch.length) return;
      const client = await pool.connect();
      try {
        await client.query('BEGIN');
        let ok = 0, err = 0;
        for (const r of batch) {
          if (r.error) { await client.query('INSERT INTO import_errors(import_id, row, error, raw) VALUES ($1,$2,$3,$4)', [importId, r.row, r.error, r.raw]); err++; io.of('/imports').to(`import:${importId}`).emit('error:row', { row: r.row, error: r.error }); }
          else ok++;
        }
        await client.query('UPDATE imports SET processed_rows=processed_rows+$1, succeeded=succeeded+$2, failed=failed+$3, last_processed_row=$4 WHERE id=$5', [batch.length, ok, err, row, importId]);
        await client.query('COMMIT');
        const cur = await pool.query('SELECT processed_rows, total_rows FROM imports WHERE id=$1', [importId]);
        io.of('/imports').to(`import:${importId}`).emit('progress', { processed: cur.rows[0].processed_rows, total: cur.rows[0].total_rows });
      } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
      batch = [];
    };
    for await (const rec of parser) {
      row++;
      const cancelled = await redis.get(`import:cancel:${importId}`);
      if (cancelled) { await pool.query("UPDATE imports SET status='cancelled' WHERE id=$1", [importId]); io.of('/imports').to(`import:${importId}`).emit('progress', { cancelled: true }); return; }
      try {
        // validate + persist to Mongo (omitted)
        batch.push({ row, raw: rec });
      } catch (e:any) { batch.push({ row, raw: rec, error: String(e) }); }
      if (batch.length >= 500) await flush();
    }
    await flush();
    await pool.query("UPDATE imports SET status='done' WHERE id=$1", [importId]);
    io.of('/imports').to(`import:${importId}`).emit('progress', { done: true });
  }, { connection: redis });
}

// src/socket/imports.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
export function registerImportsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    socket.on('import:subscribe', async ({ importId }, ack) => {
      const r = await pool.query('SELECT id, user_id, status, total_rows, processed_rows, succeeded, failed FROM imports WHERE id=$1', [importId]);
      if (!r.rows[0] || Number(r.rows[0].user_id) !== socket.data.user.id) return ack({ error: 'forbidden' });
      await socket.join(`import:${importId}`);
      const errors = await pool.query('SELECT row, error FROM import_errors WHERE import_id=$1 ORDER BY id DESC LIMIT 100', [importId]);
      ack({ status: r.rows[0], errors: errors.rows });
    });
    socket.on('import:cancel', async ({ importId }) => { await redis.set(`import:cancel:${importId}`, '1', 'EX', 300); });
  });
}

