const DocSchema = new Schema({ _id: String, workspaceId: { type: String, index: true }, title: String, content: Schema.Types.Mixed, version: { type: Number, default: 0 }, deletedAt: Date });

-- PG: references (doc → doc)
CREATE TABLE doc_refs (
  src_doc_id TEXT NOT NULL,
  dst_doc_id TEXT NOT NULL,
  workspace_id TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  PRIMARY KEY (src_doc_id, dst_doc_id)
);
CREATE INDEX ON doc_refs (dst_doc_id);
CREATE INDEX ON doc_refs (workspace_id, src_doc_id);

