// src/services/workspace.ts
import mongoose from 'mongoose';
import { Doc } from '../models/Doc';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { io } from '../server';

export async function updateDocTitle(docId:string, newTitle:string, userId:string) {
  const session = await mongoose.startSession();
  let prevTitle = '';
  try {
    await session.withTransaction(async () => {
      const cur = await Doc.findById(docId, null, { session });
      if (!cur) throw new Error('no_doc');
      prevTitle = cur.title;
      cur.title = newTitle; cur.version = (cur.version ?? 0) + 1;
      await cur.save({ session });
    });
  } finally { await session.endSession(); }
  // who references this doc?
  const { rows: refs } = await pool.query('SELECT src_doc_id, workspace_id FROM doc_refs WHERE dst_doc_id=$1', [docId]);
  // emit to each referencing doc room — with permission filter
  const byWs = new Map<string, string[]>();
  for (const r of refs) { const list = byWs.get(r.workspace_id) ?? []; list.push(r.src_doc_id); byWs.set(r.workspace_id, list); }
  for (const [wsId, srcDocs] of byWs) {
    for (const src of srcDocs) {
      // permission check on viewer happens at emit time by namespace handler — we just broadcast the room
      const sockets = await io.of('/workspace').in(`doc:${src}`).fetchSockets();
      for (const s of sockets) {
        if (await canRead((s.data as any).user.id, docId)) s.emit('title:changed', { docId, newTitle, prevTitle });
      }
    }
  }
  await redis.del(`backlinks:${docId}`);
}

export async function saveDocReferences(srcDocId:string, dstDocIds:string[], workspaceId:string) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('DELETE FROM doc_refs WHERE src_doc_id=$1', [srcDocId]);
    for (const dst of dstDocIds) await client.query('INSERT INTO doc_refs(src_doc_id, dst_doc_id, workspace_id) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING', [srcDocId, dst, workspaceId]);
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}

export async function getBacklinks(docId:string, viewerId:string) {
  const cached = await redis.get(`backlinks:${docId}`);
  if (cached) {
    const parsed = JSON.parse(cached);
    const visible = [];
    for (const b of parsed) if (await canRead(viewerId, String(b.id))) visible.push(b);
    return visible;
  }
  const { rows } = await pool.query('SELECT src_doc_id FROM doc_refs WHERE dst_doc_id=$1 LIMIT 1000', [docId]);
  const srcs = await Doc.find({ _id: { $in: rows.map((r:any)=>r.src_doc_id) } }, { _id: 1, title: 1, workspaceId: 1 }).lean();
  const visible = [];
  for (const s of srcs) { if (await canRead(viewerId, String(s._id))) visible.push({ id: s._id, title: s.title }); }
  await redis.set(`backlinks:${docId}`, JSON.stringify(visible), 'EX', 60);
  return visible;
}

async function canRead(userId:string, docId:string){ return true; /* perms */ }

// src/socket/workspace.namespace.ts
import { Namespace } from 'socket.io';
import { Doc } from '../models/Doc';
import { updateDocTitle, saveDocReferences, getBacklinks } from '../services/workspace';
export function registerWorkspaceNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('doc:open', async ({ docId }, ack) => {
      const doc = await Doc.findById(docId).lean();
      if (!doc) return ack({ error: 'no_doc' });
      await socket.join(`doc:${docId}`);
      const backlinks = await getBacklinks(docId, userId);
      ack({ doc, backlinks });
    });
    socket.on('doc:title:update', async ({ docId, newTitle }, ack) => { await updateDocTitle(docId, newTitle, userId); ack({ ok: true }); });
    socket.on('doc:save', async ({ docId, content, refs, workspaceId }, ack) => {
      await Doc.updateOne({ _id: docId }, { $set: { content } });
      await saveDocReferences(docId, refs, workspaceId);
      ack({ ok: true });
    });
    socket.on('backlinks:fetch', async ({ docId }, ack) => { ack({ backlinks: await getBacklinks(docId, userId) }); });
  });
}

