// src/hooks/useWorkspaceDoc.ts
import { useEffect, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/workspace',{auth:{token:t},transports:['websocket']}); return sock; }
export function useWorkspaceDoc(docId:string, token:string) {
  const [doc, setDoc] = useState<any>(null);
  const [backlinks, setBacklinks] = useState<any[]>([]);
  const [linkPreviews, setLinkPreviews] = useState<Record<string,string>>({}); // dstId → title
  useEffect(() => {
    const s = getSock(token);
    const open = () => s.emit('doc:open',{docId},(r:any)=>{ if(!r.error){ setDoc(r.doc); setBacklinks(r.backlinks); } });
    const onTitle = ({docId: changedId, newTitle}:any) => setLinkPreviews(prev => ({ ...prev, [changedId]: newTitle }));
    s.on('connect', open); s.on('title:changed', onTitle);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('title:changed', onTitle); };
  }, [docId, token]);
  const save = useCallback(async (content:any, refs:string[], workspaceId:string) => new Promise((res,rej)=>getSock(token).emit('doc:save',{docId,content,refs,workspaceId},(r:any)=>r.error?rej(r):res(r))), [docId, token]);
  const renameTitle = useCallback((newTitle:string) => new Promise((res,rej)=>getSock(token).emit('doc:title:update',{docId,newTitle},(r:any)=>r.error?rej(r):res(r))), [docId, token]);
  return { doc, backlinks, linkPreviews, save, renameTitle };
}
